import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { proofMissingProjectsRule } from "./proof-missing-projects.rule.js";

const ENTITY = `
  namespace Products.MyProduct.Entities.Task {
    @entity
    model Task { id: string; }
  }
  using Products.MyProduct.Entities.Task;
`;

const FEATURE_WITH_INV = `
  @feature
  namespace Products.MyProduct.Features.Lifecycle {
    @invariant(#{
      predicate: "A {@Task} has an id.",
      why: "Reason.",
    })
    op task_has_id(): void;
  }
`;

const EVAL_WITH_PROJECTS = `
  @component(#{ type: ComponentType.Agent })
  namespace Components.MyAgent {
    @eval(#{ title: "e" })
    namespace Evals.Lifecycle.E001 {
      @signal(#{
        title: "s",
        method: SignalMethod.Deterministic,
        criteria: "criteria",
        examples: #[],
      })
      @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
      op E001_01(): boolean;
    }
  }
`;

describe("proof-missing-projects rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, proofMissingProjectsRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T007.T007_05
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_proof_missing_projects:Products.A10nBlueprintEngine.Features.SystemAuthoring.proof_targets_invariant:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs:Products.A10nBlueprintEngine.Features.SystemAuthoring.proof_targets_invariant:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability_2:Products.A10nBlueprintEngine.Features.SystemAuthoring.proof_targets_invariant:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_missing_proof:Products.A10nBlueprintEngine.Features.SystemAuthoring.proof_targets_invariant:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_proof_missing_projects
    it("@signal with @projects is valid", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          ${EVAL_WITH_PROJECTS}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T007.T007_07
    it("multiple @signal ops all with @projects are valid", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "first",
                method: SignalMethod.Deterministic,
                criteria: "criteria",
                examples: #[],
              })
              @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
              op E001_01(): boolean;

              @signal(#{
                title: "second",
                method: SignalMethod.Probabilistic,
                criteria: "criteria2",
                examples: #[],
              })
              @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
              op E001_02(): boolean;
            }
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T007.T007_03
    it("@signal without @projects fires signal diagnostic", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "criteria",
                examples: #[],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/proof-missing-projects",
          message: /E001_01/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_20
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_proof_missing_projects:Products.A10nBlueprintEngine.Features.DatasetAuthoring.targets_invariant:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs:Products.A10nBlueprintEngine.Features.DatasetAuthoring.targets_invariant:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_proof_missing_projects
    it("T018_20: @dataset without @projects fires dataset diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @dataset(#{ title: "Unlabelled dataset" })
            op d001_unlabelled(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/proof-missing-projects",
          message: /d001_unlabelled/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T007.T007_08
    it("only the @signal without @projects fires — sibling with @projects is fine", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "proven",
                method: SignalMethod.Deterministic,
                criteria: "criteria",
                examples: #[],
              })
              @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
              op E001_01(): boolean;

              @signal(#{
                title: "unproven",
                method: SignalMethod.Probabilistic,
                criteria: "criteria2",
                examples: #[],
              })
              op E001_02(): boolean;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/proof-missing-projects",
          message: /E001_02/,
        });
    });
  });
});
